// Compute transform to bring extreme coordinates into reasonable range
var bounds = path.Bounds;
float scaleX = 650f / bounds.Width;
float scaleY = 350f / bounds.Height;
float scale = Math.Min(scaleX, scaleY);
canvas.Save();
canvas.Translate(-bounds.Left * scale, -bounds.Top * scale);
canvas.Scale(scale);
canvas.DrawPath(path, paint);
canvas.Restore();
